   417→            id: `parse-error-${Date.now()}-${i}`,
   418→            type: 'parsing_error',
   419→            timestamp: new Date().toISOString(),
   420→            error: error instanceof Error ? error.message : String(error),
   421→            originalLine: lines[i],
   422→            sourceFile: filePath,
   423→            lineNumber: i + 1,
   424→          });
   425→        }
   426→      }
   427→    }
   428→
   429→    return messageGraph;
   430→  }
   431→
   432→  /**
   433→   * Build chronological timeline from message graph
   434→   */
   435→  private buildTimeline(messageGraph: Map<string, ParsedEntry>): TimelineEvent[] {
   436→    const timeline: TimelineEvent[] = [];
   437→
   438→    // Find root message (no parent or parent not in graph)
   439→    let currentUuid: string | undefined;
   440→    for (const [uuid, parsed] of messageGraph) {
   441→      if (
   442→        !parsed.entry.isSidechain &&
   443→        (!parsed.entry.parentUuid || !messageGraph.has(parsed.entry.parentUuid))
   444→      ) {
   445→        currentUuid = uuid;
   446→        break;
   447→      }
   448→    }
   449→
   450→    // Walk the main conversation chain
   451→    while (currentUuid) {
   452→      const parsed = messageGraph.get(currentUuid);
   453→      if (!parsed || parsed.entry.isSidechain) break;
   454→
   455→      const entry = parsed.entry;
   456→
   457→      // Handle different entry types
   458→      if (entry.type === 'summary') {
   459→        // Summary entries don't go in timeline, they're metadata
   460→      } else if (entry.type === 'user') {
   461→        const event = this.createUserOrToolResultEvent(entry, messageGraph);
   462→        if (event) timeline.push(event);
   463→      } else if (entry.type === 'assistant') {
   464→        const event = this.createAssistantEvent(entry, messageGraph);
   465→        if (event) timeline.push(event);
   466→      }
   467→
   468→      // Find next message in chain
   469→      currentUuid = this.findNextInChain(currentUuid, messageGraph);
   470→    }
   471→
   472→    // Add parsing errors at the end
   473→    timeline.push(...this.errors);
   474→
   475→    return timeline;
   476→  }
