   652→
   653→  /**
   654→   * Generate file diffs for file-modifying tools
   655→   */
   656→  private generateFileDiffs(toolBlock: ToolCallBlock): FilePatch[] {
   657→    const patches: FilePatch[] = [];
   658→
   659→    if (toolBlock.toolName === 'Write' && toolBlock.input.file_path && toolBlock.input.content) {
   660→      const filePath = String(toolBlock.input.file_path);
   661→      const content = String(toolBlock.input.content);
   662→
   663→      patches.push({
   664→        filePath,
   665→        type: 'create',
   666→        diff: this.createUnifiedDiff(filePath, content),
   667→      });
   668→    } else if (toolBlock.toolName === 'MultiEdit' && Array.isArray(toolBlock.input.edits)) {
   669→      for (const edit of toolBlock.input.edits as any[]) {
   670→        if (edit.file_path && edit.new_string) {
   671→          patches.push({
   672→            filePath: String(edit.file_path),
   673→            type: 'create',
   674→            diff: this.createUnifiedDiff(String(edit.file_path), String(edit.new_string)),
   675→          });
   676→        }
   677→      }
   678→    }
   679→
   680→    return patches;
   681→  }
   682→
   683→  /**
   684→   * Create unified diff format
   685→   */
   686→  private createUnifiedDiff(filePath: string, content: string): string {
   687→    const lines = content.split('\n');
   688→    const lineCount = lines.length;
   689→
   690→    const diffLines: string[] = [];
   691→    diffLines.push(`--- /dev/null`);
   692→    diffLines.push(`+++ b/${filePath}`);
   693→    diffLines.push(`@@ -0,0 +1,${lineCount} @@`);
   694→
   695→    for (const line of lines) {
   696→      diffLines.push(`+${line}`);
   697→    }
   698→
   699→    return diffLines.join('\n');
   700→  }
