   710→    }
   711→
   712→    if (Array.isArray(content)) {
   713→      const textParts: string[] = [];
   714→
   715→      for (const block of content) {
   716→        if (block.type === 'text' && block.text) {
   717→          textParts.push(block.text);
   718→        }
   719→      }
   720→
   721→      return textParts.join('\n');
   722→    }
   723→
   724→    return '';
   725→  }
