      // Create a simplified text representation for the AI prompt, but keep the structure.
      // This is better than a flat markdown file.
      const simplifiedText = timeline.map(event => {
        if (event.type === 'user_prompt') return `User: ${event.content}`;
        if (event.type === 'assistant_turn') {
          const text = event.content.filter(c => c.type === 'text_block').map(c => (c as any).text).join('\n');
          const tools = event.content.filter(c => c.type === 'tool_call_block').map(c => `[Tool Call: ${(c as any).toolName}]`).join(' ');
          const thoughts = (event.thoughts || []).map(t => `[Thought: ${t.response.slice(0, 100)}...]`).join(' ');
          return `Assistant: ${text} ${tools} ${thoughts}`;
        }
        if (event.type === 'tool_result') return `[Result of ${event.toolName}: ${event.content.slice(0, 150)}...]`;
        return '';
      }).join('\n\n');

      const userPrompt = `Analyze this structured conversation timeline and extract metadata...\n\n${simplifiedText.slice(0, 50000)}`;
      // ... (rest of your API call to OpenRouter)
    }
