7. **Add Interactive Features:**

   Enhance the timeline with navigation and filtering:

   ```tsx
   // In Timeline.tsx, add a control panel
   const [filter, setFilter] = useState<'all' | 'tools' | 'errors'>('all');
   const [searchTerm, setSearchTerm] = useState('');

   const filteredTimeline = useMemo(() => {
     let events = conversation.timeline;

     // Apply type filter
     if (filter === 'tools') {
       events = events.filter(e =>
         e.type === 'assistant_turn' && e.content.some(c => c.type === 'tool_call_block')
       );
     } else if (filter === 'errors') {
