import type { APIRoute } from 'astro';
import { getPBClient, Collections, ConversationStatus, generateUniqueSlug, generateUniqueSlugFromChecksum, ensureTagsByNames } from '@/lib/pb';
import { ConversationUploadSchema } from '@howicc/schemas';
import { queueProcessing } from '@/lib/process';
import { validateApiKey } from '@/lib/auth';
import { isRateLimited, RATE_LIMITS } from '@/lib/rate-limit';

export const prerender = false;

export const POST: APIRoute = async ({ request }) => {
  // Rate limiting
  if (isRateLimited(request, RATE_LIMITS.UPLOAD.maxRequests, RATE_LIMITS.UPLOAD.windowMs)) {
    return new Response(
      JSON.stringify({ error: 'Rate limit exceeded. Please try again later.' }),
      { status: 429, headers: { 'Content-Type': 'application/json' } }
    );
  }
  try {
    // 1. Verify API key (user key, server key, or demo mode)
    const isDemoMode = import.meta.env.DEMO_MODE === 'true';
    let authenticatedUserId: string | null = null;

    if (!isDemoMode) {
      const authHeader = request.headers.get('authorization');

      if (!authHeader || !authHeader.startsWith('Bearer ')) {
        return new Response(
          JSON.stringify({ error: 'Missing or invalid authorization header' }),
          { status: 401, headers: { 'Content-Type': 'application/json' } }
        );
      }

      const apiKey = authHeader.replace('Bearer ', '');
      const pb = await getPBClient();

      // Check if it's a user API key (starts with hcc_)
      if (apiKey.startsWith('hcc_')) {
        authenticatedUserId = await validateApiKey(pb, apiKey);

        if (!authenticatedUserId) {
          return new Response(
            JSON.stringify({ error: 'Invalid API key' }),
            { status: 401, headers: { 'Content-Type': 'application/json' } }
          );
        }
      }
      // Check if it's the server API key
      else if (apiKey !== import.meta.env.SERVER_API_KEY) {
        return new Response(
          JSON.stringify({ error: 'Invalid API key' }),
          { status: 401, headers: { 'Content-Type': 'application/json' } }
        );
      }
    }

    // 2. Parse multipart form data
    const formData = await request.formData();
    const file = formData.get('file') as File | null;

    if (!file) {
      return new Response(
        JSON.stringify({ error: 'File is required' }),
        { status: 400, headers: { 'Content-Type': 'application/json' } }
      );
    }

    // 3. Extract and validate form fields
    const rawData = {
      title: formData.get('title') as string | null,
      slug: formData.get('slug') as string | null,
      description_user: formData.get('description_user') as string | null,
      visibility: (formData.get('visibility') as string | null) || 'private',
      allowListing: formData.get('allowListing') === 'true' ? true : false,
      tags: formData.get('tags') as string | null,
      checksum: formData.get('checksum') as string | null,
      source: formData.get('source') as string | null,
      messages_json: formData.get('messages_json') as string | null,
    };

    // Parse tags if provided
    let tags: string[] = [];
    if (rawData.tags) {
      try {
        tags = JSON.parse(rawData.tags);
      } catch (error) {
        return new Response(
          JSON.stringify({ error: 'Invalid tags format. Expected JSON array.' }),
          { status: 400, headers: { 'Content-Type': 'application/json' } }
        );
      }
    }

    // Validate with Zod
    const validationResult = ConversationUploadSchema.safeParse({
      title: rawData.title || undefined,
      slug: rawData.slug || undefined,
      description_user: rawData.description_user || undefined,
      visibility: rawData.visibility as 'private' | 'unlisted' | 'public',
      allowListing: rawData.allowListing,
      tags: tags.length > 0 ? tags : undefined,
      checksum: rawData.checksum || undefined,
      source: rawData.source || undefined,
    });

    if (!validationResult.success) {
      return new Response(
        JSON.stringify({
          error: 'Validation failed',
          details: validationResult.error.format(),
        }),
        { status: 400, headers: { 'Content-Type': 'application/json' } }
      );
    }

    const uploadData = validationResult.data;

    // 4. Get PocketBase client
    const pb = await getPBClient();

    // 5. Check for duplicate by checksum
    if (uploadData.checksum) {
      try {
        const duplicate = await pb
          .collection(Collections.CONVERSATIONS)
          .getList(1, 1, {
            filter: `checksum="${uploadData.checksum}"`,
          });

        if (duplicate.items[0]) {
          const existingConv = duplicate.items[0];
          return new Response(
            JSON.stringify({
              id: existingConv.id,
              slug: existingConv.slug,
              status: existingConv.status,
              url: `/p/${existingConv.slug}`,
              duplicate: true,
            }),
            { status: 409, headers: { 'Content-Type': 'application/json' } }
          );
        }
      } catch (error) {
        console.error('Error checking for duplicates:', error);
        // Continue with upload if check fails
      }
    }

    // 6. Ensure tags exist and get IDs
    const tagIds = tags.length > 0 ? await ensureTagsByNames(pb, tags) : [];

    // 7. Generate title and slug
    const title = uploadData.title || file.name.replace(/\.md$/i, '') || 'Untitled Conversation';
    // Use first 8 chars of checksum as slug (deterministic), or generate random if no checksum
    const uniqueSlug = uploadData.checksum
      ? await generateUniqueSlugFromChecksum(pb, uploadData.checksum)
      : await generateUniqueSlug(pb);

    // 8. Ensure we have an authenticated user (required for user field)
    if (!authenticatedUserId) {
      return new Response(
        JSON.stringify({ error: 'User authentication required. Use a user API key (hcc_*) to create conversations.' }),
        { status: 401, headers: { 'Content-Type': 'application/json' } }
      );
    }

    // 9. Create FormData for PocketBase
    const pbFormData = new FormData();
    pbFormData.append('title', title);
    pbFormData.append('slug', uniqueSlug);
    pbFormData.append('status', ConversationStatus.UPLOADED);
    pbFormData.append('source', uploadData.source || 'claude');
    pbFormData.append('visibility', uploadData.visibility);
    pbFormData.append('allowListing', String(uploadData.allowListing || false));
    pbFormData.append('viewsTotal', '0');
    pbFormData.append('viewsUnique24h', '0');
    pbFormData.append('user', authenticatedUserId); // Bind conversation to user

    if (uploadData.checksum) {
      pbFormData.append('checksum', uploadData.checksum);
    }

    if (uploadData.description_user) {
      pbFormData.append('description_user', uploadData.description_user);
    }

    if (tagIds.length > 0) {
      pbFormData.append('tags', JSON.stringify(tagIds));
    }

    // Append messages JSON if provided
    if (rawData.messages_json) {
      try {
        // Validate it's valid JSON
        JSON.parse(rawData.messages_json);
        pbFormData.append('messages_json', rawData.messages_json);
      } catch (error) {
        console.error('Invalid messages_json format:', error);
        // Continue without messages_json if invalid
      }
    }

    // Append the file
    pbFormData.append('md', file, file.name);

    // 10. Create record in PocketBase (using admin client, so we can set user field directly)
    const created = await pb.collection(Collections.CONVERSATIONS).create(pbFormData);

    // 11. Queue for processing
    queueProcessing(pb, created.id);

    // 12. Return success response
    return new Response(
      JSON.stringify({
        id: created.id,
        slug: created.slug,
        status: created.status,
        url: `/p/${created.slug}`,
      }),
      { status: 201, headers: { 'Content-Type': 'application/json' } }
    );
  } catch (error) {
    console.error('Error in /api/conversations:', error);

    // If it's a PocketBase ClientResponseError, extract validation details
    if (error && typeof error === 'object' && 'response' in error) {
      const pbError = error as any;
      if (pbError.response?.data) {
        console.error('PocketBase validation errors:', JSON.stringify(pbError.response.data, null, 2));
        return new Response(
          JSON.stringify({
            error: 'Validation failed',
            details: pbError.response.data,
          }),
          { status: pbError.status || 400, headers: { 'Content-Type': 'application/json' } }
        );
      }
    }

    return new Response(
      JSON.stringify({
        error: 'Internal server error',
        details: error instanceof Error ? error.message : 'Unknown error',
      }),
      { status: 500, headers: { 'Content-Type': 'application/json' } }
    );
  }
};

