     1→import { AIAnalysisSchema, type AIAnalysis } from './schemas';
     2→
     3→/**
     4→ * Analyze a conversation using OpenRouter's Claude model
     5→ */
     6→export async function analyzeConversation(markdown: string): Promise<AIAnalysis> {
     7→  const systemPrompt = `You are a precise archivist analyzing chat conversations.
     8→Your task is to extract metadata that helps users understand and find conversations.
     9→
    10→Return ONLY valid JSON with this exact structure:
    11→{
    12→  "title": "A concise title (max 80 characters)",
    13→  "summary": "A 3-6 sentence overview of the conversation's purpose and outcome",
    14→  "takeaways": ["Key point 1", "Key point 2", ...],
    15→  "generated_tags": ["tag1", "tag2", ...],
    16→  "safety_flags": {
    17→    "pii": false,
    18→    "secrets": false
    19→  }
    20→}
    21→
    22→Guidelines:
    23→- title: Should be descriptive and searchable
    24→- summary: Focus on what was accomplished or discussed
    25→- takeaways: 3-8 bullet points of key insights or outcomes
    26→- generated_tags: 5-12 relevant tags (lowercase, use hyphens for multi-word tags)
    27→- safety_flags.pii: Set to true if email addresses, phone numbers, or personal info detected
    28→- safety_flags.secrets: Set to true if API keys, tokens, passwords, or credentials detected`;
    29→
    30→  const userPrompt = `Analyze this conversation and extract metadata:
    31→
    32→<<<BEGIN_CONVERSATION>>>
    33→${markdown.slice(0, 50000)}
    34→<<<END_CONVERSATION>>>
    35→
    36→Return ONLY the JSON object, no additional text.`;
    37→
    38→  try {
    39→    const response = await fetch('https://openrouter.ai/api/v1/chat/completions', {
    40→      method: 'POST',
    41→      headers: {
    42→        'Authorization': `Bearer ${import.meta.env.OPENROUTER_API_KEY}`,
    43→        'Content-Type': 'application/json',
    44→        'HTTP-Referer': import.meta.env.PUBLIC_SITE_URL,
    45→        'X-Title': 'How I Claude Code',
    46→      },
    47→      body: JSON.stringify({
    48→        model: import.meta.env.OPENROUTER_MODEL || 'anthropic/claude-3.5-sonnet',
    49→        messages: [
    50→          { role: 'system', content: systemPrompt },
    51→          { role: 'user', content: userPrompt },
    52→        ],
    53→        temperature: 0.3,
    54→        max_tokens: 2000,
    55→        response_format: { type: 'json_object' },
    56→      }),
    57→    });
    58→
    59→    if (!response.ok) {
    60→      throw new Error(`OpenRouter API error: ${response.statusText}`);
    61→    }
    62→
    63→    const data = await response.json();
    64→    const text = data.choices?.[0]?.message?.content || '{}';
    65→
    66→    // Parse and validate the response
    67→    const parsed = JSON.parse(text);
    68→    const validated = AIAnalysisSchema.parse(parsed);
    69→
    70→    return validated;
    71→  } catch (error) {
    72→    console.error('AI analysis failed:', error);
    73→
    74→    // Return a basic fallback analysis
    75→    return {
    76→      title: 'Conversation',
    77→      summary: 'Failed to analyze conversation content.',
    78→      takeaways: [],
    79→      generated_tags: ['unprocessed'],
    80→      safety_flags: {
    81→        pii: false,
    82→        secrets: false,
    83→      },
    84→    };
    85→  }
    86→}
    87→
    88→/**
    89→ * Simple, fast regex-based safety checks for howi.cc
    90→ * - Keep patterns lean to minimize false positives
    91→ * - Do not do network calls or heavy parsing
    92→ */
    93→export type RedactionType =
    94→  | "email"
    95→  | "phone"
    96→  | "ssn"
    97→  | "uuid"
    98→  | "dotenv_kv"
    99→  | "password_kv"
   100→  | "ssh_private_key"
   101→  | "rsa_private_key"
   102→  | "ec_private_key"
   103→  | "pgp_private_key"
   104→  | "openai_key"
   105→  | "stripe_key"
   106→  | "github_token"
