        'Authorization': `Bearer ${import.meta.env.OPENROUTER_API_KEY}`,
        'Content-Type': 'application/json',
        'HTTP-Referer': import.meta.env.PUBLIC_SITE_URL,
        'X-Title': 'How I Claude Code',
      },
