import { marked } from "marked";
import DOMPurify from "dompurify";
// @ts-ignore - jsdom types are available but may not resolve in SSR context
import { JSDOM } from "jsdom";
import BaseLayout from "@/layouts/BaseLayout.astro";
import { ConversationStatus } from "@/lib/pb";
import { safeFetch } from "@/lib/ssrf-protection";
import { ConversationResponseSchema } from "@howicc/schemas";
import type { ConversationRecord, Tag } from "@howicc/schemas";
import { Timeline } from "@/components/conversation/Timeline";

export const prerender = false;

const { slug } = Astro.params;

if (!slug) {
  return Astro.redirect("/404");
}

// Fetch conversation from API
let conversation: ConversationRecord | null = null;
let tags: Tag[] = [];
let fileUrl: string | null = null;

try {
  const response = await fetch(`${Astro.url.origin}/api/conversation/${slug}`, {
    headers: {
      Cookie: Astro.request.headers.get('cookie') || '',
    },
  });

  if (response.ok) {
    const data = await response.json();
    // Validate response with Zod schema
    const validated = ConversationResponseSchema.parse(data);
    conversation = validated.conversation;
    tags = validated.tags;
    fileUrl = validated.fileUrl;
  }
} catch (error) {
  console.error("Error fetching conversation:", error);
}

if (!conversation) {
  return Astro.redirect("/404");
}

// Prepare content for display
let contentHtml = "";

// Initialize DOMPurify for server-side sanitization
const dom = new JSDOM('');
// @ts-ignore - DOMPurify works with JSDOM window
const purify = DOMPurify(dom.window);

if (conversation.messages_json && conversation.messages_json.length > 0) {
  // Render structured messages
  const markdownContent = conversation.messages_json
    .map((msg) => {
      const roleLabel = msg.role === "user" ? "👤 Human" : "🤖 Claude";
      return `## ${roleLabel}\n\n${msg.content}`;
    })
    .join("\n\n---\n\n");

  const rawHtml = await marked.parse(markdownContent);
  // Sanitize HTML to prevent XSS
  contentHtml = purify.sanitize(rawHtml, {
    ALLOWED_TAGS: ['p', 'br', 'strong', 'em', 'u', 'h1', 'h2', 'h3', 'h4', 'h5', 'h6', 'ul', 'ol', 'li', 'blockquote', 'code', 'pre', 'a'],
    ALLOWED_ATTR: ['href', 'class'],
    ALLOW_DATA_ATTR: false,
  });
} else if (conversation.md && fileUrl) {
  // Fallback to raw markdown file
  try {
    // SSRF protection: Only allow PocketBase file URLs
    const pbUrl = new URL(import.meta.env.PB_URL);
    const allowedHosts = [pbUrl.hostname];

    const response = await safeFetch(fileUrl, allowedHosts, 5000);
    if (response && response.ok) {
      const markdown = await response.text();
      const rawHtml = await marked.parse(markdown);
      // Sanitize HTML to prevent XSS
      contentHtml = purify.sanitize(rawHtml, {
        ALLOWED_TAGS: ['p', 'br', 'strong', 'em', 'u', 'h1', 'h2', 'h3', 'h4', 'h5', 'h6', 'ul', 'ol', 'li', 'blockquote', 'code', 'pre', 'a'],
        ALLOWED_ATTR: ['href', 'class'],
        ALLOW_DATA_ATTR: false,
      });
    } else {
      contentHtml = "<p>Failed to load conversation content.</p>";
    }
  } catch (error) {
    console.error("Error fetching markdown file:", error);
    contentHtml = "<p>Failed to load conversation content.</p>";
  }
}

// Format date
let formattedDate = "Unknown";
try {
  const createdDate = new Date(conversation.created);
  if (!isNaN(createdDate.getTime())) {
    formattedDate = createdDate.toLocaleDateString("en-US", {
      year: "numeric",
      month: "long",
      day: "numeric"
    });
  }
} catch (error) {
  console.error("Error formatting date:", error);
}

// Check if still processing
const isProcessing = conversation.status === ConversationStatus.UPLOADED;
const needsReview = conversation.status === ConversationStatus.NEEDS_REVIEW;
---

<BaseLayout
  title={conversation.title}
  description={conversation.summary ||
    conversation.description_user ||
    "A Claude conversation"}
>
  <div class="max-w-4xl mx-auto">
    <!-- Header -->
    <header class="mb-8">
      <div class="mb-4">
        <h1 class="text-3xl sm:text-4xl font-bold text-base-900 mb-3">
          {conversation.title}
        </h1>
        <div class="flex flex-wrap items-center gap-3 text-sm text-base-600">
          <span>📅 {formattedDate}</span>
          <span>•</span>
          <span>🔖 {conversation.source}</span>
          {
            isProcessing && (
              <>
                <span>•</span>
                <span class="inline-flex items-center gap-1.5 text-primary-600">
                  <svg
                    class="animate-spin h-4 w-4"
                    xmlns="http://www.w3.org/2000/svg"
                    fill="none"
                    viewBox="0 0 24 24"
                  >
                    <circle
                      class="opacity-25"
                      cx="12"
                      cy="12"
                      r="10"
                      stroke="currentColor"
                      stroke-width="4"
                    />
                    <path
                      class="opacity-75"
                      fill="currentColor"
                      d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"
                    />
                  </svg>
                  Processing...
                </span>
              </>
            )
          }
          {
            needsReview && (
              <>
                <span>•</span>
                <span class="text-yellow-600">⚠️ Needs Review</span>
              </>
            )
          }
        </div>
      </div>

      <!-- Tags -->
      {
        tags.length > 0 && (
          <div class="flex flex-wrap gap-2">
            {tags.map((tag) => (
              <span class="inline-flex items-center px-3 py-1 rounded-full text-xs font-medium bg-primary-100 text-primary-800">
                {tag.name}
              </span>
            ))}
          </div>
        )
      }
    </header>

    <!-- Summary Section -->
    {
      (conversation.summary || conversation.description_user) && (
        <section class="bg-white rounded-3xl border border-base-200 p-6 mb-8">
          <h2 class="text-sm font-semibold mb-3">📝 Summary</h2>

          {conversation.summary && (
            <div class="prose prose-sm max-w-none mb-4">
              <p class="text-base-700">{conversation.summary}</p>
            </div>
          )}

          {conversation.description_user && (
            <div class="prose prose-sm max-w-none text-base-600 italic">
              <p>{conversation.description_user}</p>
            </div>
          )}

          {conversation.takeaways && conversation.takeaways.length > 0 && (
            <div class="mt-4 pt-4 border-t border-base-200">
              <h3 class="text-sm font-semibold mb-2">Key Takeaways:</h3>
              <ul class="space-y-1.5">
                {conversation.takeaways.map((takeaway) => (
                  <li class="text-sm text-base-700 flex items-start gap-2">
                    <span class="text-primary-500 mt-0.5">•</span>
                    <span>{takeaway}</span>
                  </li>
                ))}
              </ul>
            </div>
          )}
        </section>
      )
    }

    <!-- Conversation Content -->
    <article
      class="prose prose-base max-w-none bg-white rounded-3xl border border-base-200 p-8"
      set:html={contentHtml}
    />

    <!-- Share Button -->
    <div class="mt-8 flex justify-center">
      <button
        id="copyLinkBtn"
        class="inline-flex items-center gap-2 px-6 py-3 bg-primary-600 text-white rounded-full font-medium hover:bg-primary-700 transition-colors"
      >
        <svg
          xmlns="http://www.w3.org/2000/svg"
          class="h-5 w-5"
          fill="none"
          viewBox="0 0 24 24"
          stroke="currentColor"
        >
          <path
            stroke-linecap="round"
            stroke-linejoin="round"
            stroke-width="2"
            d="M8.684 13.342C8.886 12.938 9 12.482 9 12c0-.482-.114-.938-.316-1.342m0 2.684a3 3 0 110-2.684m0 2.684l6.632 3.316m-6.632-6l6.632-3.316m0 0a3 3 0 105.367-2.684 3 3 0 00-5.367 2.684zm0 9.316a3 3 0 105.368 2.684 3 3 0 00-5.368-2.684z"
          ></path>
        </svg>
        <span>Copy Link</span>
      </button>
    </div>
  </div>
</BaseLayout>

<script>
  // Copy link functionality
  const btn = document.getElementById("copyLinkBtn");
  if (btn) {
    btn.addEventListener("click", async () => {
      try {
        await navigator.clipboard.writeText(window.location.href);
        const span = btn.querySelector("span");
        if (span) {
          const original = span.textContent;
          span.textContent = "Copied!";
          setTimeout(() => {
            span.textContent = original;
          }, 2000);
        }
      } catch (error) {
        console.error("Failed to copy:", error);
      }
    });
  }
</script>

